{
  "openapi": "3.0.0",
   "info": {
       "title": "Security Concerns API",
       "description": "API for analyzing security concerns for a Node.js REST API",
       "version": "1.0.0"
   },
   "servers": [
       {
           "url": "https://api.example.com"
       }
   ],
   "tags": [
       {
           "name": "security-concerns",
           "description": "Endpoints for analyzing security concerns"
       }
   ],
   "paths": {
       "/analyze": {
           "post": {
               "tags": [
                   "security-concerns"
               ],
               "summary": "Analyze security concerns for a Node.js REST API",
               "description": "Analyze security concerns for a Node.js REST API",
               "requestBody": {
                   "required": true,
                   "content": {
                       "application/json": {
                           "schema": {
                               "$ref": "#/components/schemas/SecurityConcernsRequest"
                           }
                       }
                   }
               },
               "responses": {
                   "200": {
                       "description": "Security concerns analysis result",
                       "content": {
                           "application/json": {
                               "schema": {
                                   "$ref": "#/components/schemas/SecurityConcernsResponse"
                               }
                           }
                       }
                   },
                   "400": {
                       "description": "Invalid request"
                   },
                   "500": {
                       "description": "Internal server error"
                   }
               }
           }
       }
   },
   "components": {
       "schemas": {
           "SecurityConcernsRequest": {
               "type": "object",
               "required": [
                   "apiEndpoint",
                   "apiKey"
               ],
               "properties": {
                   "apiEndpoint": {
                       "type": "string",
                       "description": "API endpoint to analyze"
                   },
                   "apiKey": {
                       "type": "string",
                       "description": "API key for authentication"
                   }
               }
           },
           "SecurityConcernsResponse": {
               "type": "object",
               "properties": {
                   "securityConcerns": {
                       "type": "array",
                       "items": {
                           "$ref": "#/components/schemas/SecurityConcern"
                       }
                   }
               }
           },
           "SecurityConcern": {
               "type": "object",
               "properties": {
                   "id": {
                       "type": "integer",
                       "description": "Security concern ID"
                   },
                   "description": {
                       "type": "string",
                       "description": "Security concern description"
                   },
                   "severity": {
                       "type": "string",
                       "description": "Security concern severity"
                   }
               }
           }
       }
   }
}

